from fastapi import FastAPI, Depends, Header, HTTPException
from typing import Optional
import secrets

app = FastAPI()


# Simple dependency — acts as an auth guard
async def verify_api_key(x_api_key: str = Header()):
    if not secrets.compare_digest(x_api_key, "my-secret-key"):
        raise HTTPException(status_code=403, detail="Invalid API key")
    return {"tier": "premium"}


# Dependency with cleanup using yield
async def get_db_session():
    session = {"id": 1, "connected": True}  # Simulated DB session
    try:
        yield session
    finally:
        session["connected"] = False  # Cleanup after response


# Nested dependency — auth depends on api_key check
async def get_current_user(
    auth: dict = Depends(verify_api_key),
    db: dict = Depends(get_db_session),
):
    return {"user": "alice", "tier": auth["tier"], "db": db}


@app.get("/protected")
async def protected_route(user: dict = Depends(get_current_user)):
    return {"message": f"Hello {user['user']}", "tier": user["tier"]}


# Class-based dependency
class Pagination:
    def __init__(self, skip: int = 0, limit: int = 10):
        self.skip = skip
        self.limit = limit


@app.get("/items")
async def list_items(pagination: Pagination = Depends()):
    return {"skip": pagination.skip, "limit": pagination.limit}
